    }

    /* ──────────────────────────────────────────
     * DASHBOARD — Stats Polling
     * ────────────────────────────────────────── */
    function loadDashboard() {
        ajax('crawlguard_get_realtime_stats').done(function (res) {
            if (!res.success) return;
            var s = res.data.stats || {};
            $('#cg-total-requests').text(fmt(s.total_requests || 0));
            $('#cg-bots-detected').text(fmt(s.bots_detected || 0));
            $('#cg-revenue').text('$' + parseFloat(s.total_revenue || 0).toFixed(2));
            $('#cg-challenges').text(fmt(s.challenges_served || 0));

            renderRecentActivity(res.data.recent || []);
        });

        ajax('crawlguard_get_analytics').done(function (res) {
            if (!res.success) return;
            var d = res.data || {};
            renderBotDistribution(d.bot_distribution || []);
        });
