function analyzeHeuristically(headers, userAgent) {
    let score = 0;
    const signals = [];

    if (!headers.get('accept-language')) { score += 20; signals.push('missing_accept_language'); }
    if (!headers.get('accept-encoding')) { score += 15; signals.push('missing_accept_encoding'); }
    if (!headers.get('referer')) { score += 10; signals.push('missing_referer'); }

    const ua = userAgent.toLowerCase();
    if (/bot|crawler|spider/.test(ua)) { score += 25; signals.push('generic_bot_ua'); }
    if (/python-requests|axios|curl/.test(ua)) { score += 30; signals.push('programmatic_client'); }
    if (/scrapy|puppeteer|playwright/.test(ua)) { score += 35; signals.push('scraping_framework'); }
    if (!ua || ua === '') { score += 40; signals.push('empty_user_agent'); }
    if (headers.get('x-crawlera-profile')) { score += 30; signals.push('scraping_service'); }

    return { score: Math.min(score, 100), signals };
