export default {
    async fetch(request, env) {
        const url = new URL(request.url);
        const method = request.method;

        // CORS preflight
        if (method === 'OPTIONS') {
            return new Response(null, {
                status: 204,
                headers: {
                    'Access-Control-Allow-Origin': '*',
                    'Access-Control-Allow-Methods': 'GET, POST, PUT, OPTIONS',
                    'Access-Control-Allow-Headers': 'Content-Type, X-API-Key, X-Site-Id',
                },
            });
        }

        // Health
        if (url.pathname === '/v1/status' && method === 'GET') {
            return jsonOk({
                service: 'crawlguard-api-dev',
                version: '1.0.0-dev',
                environment: 'development',
                timestamp: new Date().toISOString(),
            });
        }

        // If DATABASE_URL is set, delegate to production worker
        if (env.DATABASE_URL) {
            const { default: prodWorker } = await import('./production-worker.js');
            return prodWorker.fetch(request, env);
        }

        // Mock responses for dev without DB
        if (url.pathname === '/v1/detect' && method === 'POST') {
            const body = await request.json();
            const ua = (body.user_agent || '').toLowerCase();
            const isBot = /gptbot|claudebot|ccbot|bytespider|google-extended/.test(ua);
            return jsonOk({
                bot_detected: isBot,
                bot_name: isBot ? 'mock_bot' : null,
                confidence_score: isBot ? 90 : 5,
                action: isBot ? 'challenge' : 'allow',
            });
        }

        if (url.pathname === '/v1/analytics' && method === 'GET') {
            return jsonOk({
                overview: { total_requests: 0, bot_requests: 0, monetized_requests: 0, total_revenue: 0, unique_bots: 0 },
                top_bots: [],
                recent_activity: [],
                daily_stats: [],
            });
        }

        return jsonError(404, `Dev: Route ${method} ${url.pathname} not found`);
    },
};

