const express = require('express');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const dotenv = require('dotenv');
const { Pool } = require('pg');

const app = express();
const port = process.env.PORT || 3000;

const root = path.resolve(__dirname, '..');
const webRoot = __dirname;
dotenv.config({ path: path.resolve(root, '..', '.env') });

const databaseUrl = process.env.DATABASE_URL || process.env.DATABASE_URL_PRODUCTION;
const adminApiKey = process.env.ADMIN_API_KEY || '';
const isDatabaseEnabled = Boolean(databaseUrl);

const pool = isDatabaseEnabled
    ? new Pool({
        connectionString: databaseUrl,
        ssl: { rejectUnauthorized: false },
    })
    : null;

const dataDir = path.join(webRoot, 'data');
const keysFile = path.join(dataDir, 'keys.json');
const downloadsDir = path.join(webRoot, 'public', 'downloads');

if (!fs.existsSync(dataDir)) {
    fs.mkdirSync(dataDir, { recursive: true });
}

if (!fs.existsSync(keysFile)) {
    fs.writeFileSync(keysFile, JSON.stringify({ keys: [] }, null, 2), 'utf8');
}

app.use(express.json());
app.use('/downloads', express.static(downloadsDir));
app.use(express.static(path.join(webRoot, 'public')));

const jsonOk = (res, data = {}) => res.json({ ok: true, ...data });
const jsonError = (res, status, message) => res.status(status).json({ ok: false, message });

const normalizeApiKey = (apiKey) => String(apiKey || '').trim();
const keyPrefix = (apiKey) => normalizeApiKey(apiKey).slice(0, 12);
const hashApiKey = (apiKey) => crypto.createHash('sha256').update(normalizeApiKey(apiKey)).digest('hex');

const requireApiKey = async (req, res, next) => {
    const apiKey = normalizeApiKey(req.header('x-api-key'));
    if (!apiKey) {
        return jsonError(res, 401, 'Missing X-API-Key');
    }

    if (!pool) {
        if (apiKey === adminApiKey && adminApiKey !== '') {
            return next();
        }
        return jsonError(res, 401, 'Invalid API key');
    }

    try {
        const hashed = hashApiKey(apiKey);
        const query = `
            UPDATE api_keys
            SET last_used_at = NOW()
            WHERE key_hash = $1 AND status = 'active'
            RETURNING id
        `;
        const result = await pool.query(query, [hashed]);

        if (result.rowCount === 0) {
            return jsonError(res, 401, 'Invalid API key');
        }

        return next();
    } catch (error) {
        return jsonError(res, 500, 'API key verification failed');
    }
};

